  ('b1000001-0000-0000-0000-000000000005', 'Race condition in balance update logic', 'CWE-362', 'balance = get_balance(); balance += amount; set_balance(balance)', 2, 'high', '["payment-gateway-v3"]', 8.1, 0.65, 78.4, 'investigating', now() - interval '4 hours'),
