INSERT INTO glasswing_findings (id, finding_id, codebase, file_path, line_start, line_end, vuln_class, severity, confidence, exploit_chain_id, chain_position, chain_depth, poc_code, hunt_agent_id, description, remediation_suggestion, status, ingested_at, root_cause_group_id, scan_run_id, title)
VALUES
  ('c1000001-0000-0000-0000-000000000001', 'MYTHOS-2026-0001', 'payment-gateway-v3', 'src/handlers/webhook.py', 142, 158, 'CWE-502', 'critical', 0.97, 'chain-001', 1, 3, 'import pickle; payload = pickle.loads(base64.b64decode(request.body))', 'hunt-agent-07', 'Untrusted pickle deserialization in webhook payload handler allows arbitrary code execution', 'Use json.loads() or implement a safe deserializer with allowlisted classes', 'confirmed', now() - interval '3 hours', 'b1000001-0000-0000-0000-000000000001', 'a1000001-0000-0000-0000-000000000001', 'RCE via Pickle Deserialization in Webhook Handler'),
  ('c1000001-0000-0000-0000-000000000002', 'MYTHOS-2026-0002', 'payment-gateway-v3', 'src/api/transfers.py', 89, 102, 'CWE-362', 'high', 0.92, 'chain-001', 2, 3, E'balance = db.get_balance(account_id)\nbalance += amount\ndb.set_balance(account_id, balance)', 'hunt-agent-12', 'TOCTOU race condition in transfer logic enables double-spend attack', 'Use SELECT FOR UPDATE or atomic increment operations', 'confirmed', now() - interval '3 hours', 'b1000001-0000-0000-0000-000000000005', 'a1000001-0000-0000-0000-000000000001', 'Double-Spend Race Condition in Transfer API'),
  ('c1000001-0000-0000-0000-000000000003', 'MYTHOS-2026-0003', 'payment-gateway-v3', 'src/handlers/callback.py', 201, 215, 'CWE-918', 'high', 0.89, 'chain-001', 3, 3, 'resp = requests.get(callback_url, allow_redirects=True, timeout=30)', 'hunt-agent-22', 'SSRF in payment callback handler allows internal network scanning and cloud metadata access', 'Validate URL against allowlist, disable redirects, block RFC1918 ranges', 'confirmed', now() - interval '3 hours', 'b1000001-0000-0000-0000-000000000004', 'a1000001-0000-0000-0000-000000000001', 'SSRF in Payment Callback Handler'),
  ('c1000001-0000-0000-0000-000000000004', 'MYTHOS-2026-0004', 'identity-service', 'internal/auth/jwt.go', 67, 84, 'CWE-347', 'critical', 0.98, 'chain-002', 1, 2, E'token, err := jwt.Parse(tokenStr, keyFunc, jwt.WithValidMethods([]string{"HS256","RS256","none"}))', 'hunt-agent-03', 'Algorithm confusion attack allows forging JWT tokens with "none" algorithm', 'Remove "none" from allowed algorithms list, enforce RS256 only', 'patched', now() - interval '6 hours', 'b1000001-0000-0000-0000-000000000003', 'a1000001-0000-0000-0000-000000000002', 'JWT Algorithm Confusion Bypass'),
  ('c1000001-0000-0000-0000-000000000005', 'MYTHOS-2026-0005', 'identity-service', 'internal/auth/session.go', 134, 148, 'CWE-384', 'high', 0.85, 'chain-002', 2, 2, E'session.Token = generateToken()\n// old session not invalidated', 'hunt-agent-03', 'Session fixation: old session tokens remain valid after privilege escalation', 'Invalidate all prior sessions on role change or re-authentication', 'confirmed', now() - interval '6 hours', NULL, 'a1000001-0000-0000-0000-000000000002', 'Session Fixation After Privilege Change'),
  ('c1000001-0000-0000-0000-000000000006', 'MYTHOS-2026-0006', 'identity-service', 'internal/api/users.go', 223, 241, 'CWE-502', 'critical', 0.94, NULL, NULL, NULL, E'var user User\nif err := gob.NewDecoder(r.Body).Decode(&user); err != nil {', 'hunt-agent-18', 'Gob deserialization of untrusted request body enables type confusion attacks', 'Use JSON with strict schema validation instead of gob for external inputs', 'confirmed', now() - interval '6 hours', 'b1000001-0000-0000-0000-000000000001', 'a1000001-0000-0000-0000-000000000002', 'Type Confusion via Gob Deserialization'),
  ('c1000001-0000-0000-0000-000000000007', 'MYTHOS-2026-0007', 'data-pipeline-etl', 'ingestion/sql_loader.py', 56, 72, 'CWE-89', 'critical', 0.96, 'chain-003', 1, 2, E'query = f"INSERT INTO {schema}.{table} SELECT * FROM staging WHERE source = \\''{source}\\''\"', 'hunt-agent-31', 'SQL injection via f-string interpolation in ETL loader allows data exfiltration', 'Use parameterized queries or prepared statements', 'confirmed', now() - interval '2 hours', 'b1000001-0000-0000-0000-000000000002', 'a1000001-0000-0000-0000-000000000003', 'SQL Injection in ETL SQL Loader'),
  ('c1000001-0000-0000-0000-000000000008', 'MYTHOS-2026-0008', 'data-pipeline-etl', 'ingestion/file_handler.py', 31, 45, 'CWE-22', 'high', 0.88, 'chain-003', 2, 2, E'output_path = os.path.join(DATA_DIR, filename)\nwith open(output_path, "wb") as f:', 'hunt-agent-31', 'Path traversal in file upload allows overwriting pipeline configs', 'Use secure_filename() and verify resolved path stays within DATA_DIR', 'confirmed', now() - interval '2 hours', 'b1000001-0000-0000-0000-000000000006', 'a1000001-0000-0000-0000-000000000003', 'Path Traversal in File Upload Handler'),
  ('c1000001-0000-0000-0000-000000000009', 'MYTHOS-2026-0009', 'data-pipeline-etl', 'transforms/dynamic_eval.py', 88, 99, 'CWE-94', 'critical', 0.93, 'chain-004', 1, 2, E'result = eval(transform_expression, {"__builtins__": {}}, context)', 'hunt-agent-44', 'Code injection via eval() in dynamic transform expressions despite builtins restriction', 'Replace eval with AST-based safe expression evaluator', 'confirmed', now() - interval '2 hours', 'b1000001-0000-0000-0000-000000000002', 'a1000001-0000-0000-0000-000000000003', 'Code Injection via eval() in Transform Engine'),
  ('c1000001-0000-0000-0000-000000000010', 'MYTHOS-2026-0010', 'payment-gateway-v3', 'src/middleware/auth.py', 45, 62, 'CWE-287', 'high', 0.87, NULL, NULL, NULL, 'if hmac.compare_digest(sig, expected_sig) or bypass_mode:', 'hunt-agent-15', 'Authentication bypass via debug mode flag left in production middleware', 'Remove bypass_mode condition, add deploy-time check for debug flags', 'confirmed', now() - interval '4 hours', NULL, 'a1000001-0000-0000-0000-000000000001', 'Auth Bypass via Debug Mode in Middleware'),
  ('c1000001-0000-0000-0000-000000000011', 'MYTHOS-2026-0011', 'payment-gateway-v3', 'lib/crypto/sign.py', 112, 128, 'CWE-326', 'medium', 0.82, NULL, NULL, NULL, 'key = RSA.generate(1024)', 'hunt-agent-28', 'Weak 1024-bit RSA key generation for transaction signing', 'Upgrade to minimum 2048-bit RSA or switch to Ed25519', 'confirmed', now() - interval '4 hours', NULL, 'a1000001-0000-0000-0000-000000000001', 'Weak RSA Key Size for Transaction Signing'),
  ('c1000001-0000-0000-0000-000000000012', 'MYTHOS-2026-0012', 'identity-service', 'internal/store/cache.go', 178, 195, 'CWE-200', 'medium', 0.79, NULL, NULL, NULL, E'cache.Set(fmt.Sprintf("user:%s", userId), userData, 24*time.Hour)', 'hunt-agent-09', 'Sensitive user data cached without encryption, accessible via cache-timing side channel', 'Encrypt cached values at rest or reduce cache TTL for sensitive fields', 'confirmed', now() - interval '6 hours', NULL, 'a1000001-0000-0000-0000-000000000002', 'Unencrypted PII in Cache Layer')
