INSERT INTO glasswing_patches (id, root_cause_id, finding_id, patch_type, patch_code, patch_diff, regression_test_code, regression_test_passed, breaking_change, review_status, generated_by, created_at, target_file, target_codebase)
VALUES
  ('f1000001-0000-0000-0000-000000000001', 'b1000001-0000-0000-0000-000000000003', 'c1000001-0000-0000-0000-000000000004', 'safe_additive', E'token, err := jwt.Parse(tokenStr, keyFunc, jwt.WithValidMethods([]string{"RS256"}))', E'--- a/internal/auth/jwt.go\n+++ b/internal/auth/jwt.go\n@@ -67,7 +67,7 @@\n-\ttoken, err := jwt.Parse(tokenStr, keyFunc, jwt.WithValidMethods([]string{"HS256","RS256","none"}))\n+\ttoken, err := jwt.Parse(tokenStr, keyFunc, jwt.WithValidMethods([]string{"RS256"}))', E'func TestJWTAlgorithmRestriction(t *testing.T) {\n\tnoneToken := jwt.NewWithClaims(jwt.SigningMethodNone, claims)\n\t_, err := validateToken(noneToken.Raw)\n\tassert.ErrorContains(t, err, "signing method none is invalid")\n}', true, false, 'approved', 'mythos-preview', now() - interval '6 hours', 'internal/auth/jwt.go', 'identity-service'),
  ('f1000001-0000-0000-0000-000000000002', 'b1000001-0000-0000-0000-000000000001', 'c1000001-0000-0000-0000-000000000001', 'safe_additive', E'import json\npayload = json.loads(request.body)\nvalidate(payload, WEBHOOK_SCHEMA)', E'--- a/src/handlers/webhook.py\n+++ b/src/handlers/webhook.py\n@@ -142,4 +142,6 @@\n-import pickle\n-payload = pickle.loads(base64.b64decode(request.body))\n+import json\n+from jsonschema import validate\n+payload = json.loads(request.body)\n+validate(payload, WEBHOOK_SCHEMA)', E'def test_no_pickle_deserialization():\n    malicious = base64.b64encode(pickle.dumps(MaliciousClass()))\n    response = client.post("/webhooks", data=malicious)\n    assert response.status_code == 400', true, false, 'pending_review', 'mythos-preview', now() - interval '3 hours', 'src/handlers/webhook.py', 'payment-gateway-v3'),
  ('f1000001-0000-0000-0000-000000000003', 'b1000001-0000-0000-0000-000000000002', 'c1000001-0000-0000-0000-000000000007', 'safe_additive', E'from sqlalchemy import text\nquery = text("INSERT INTO :schema.:table SELECT * FROM staging WHERE source = :source")\ndb.execute(query, {"schema": schema, "table": table, "source": source})', E'--- a/ingestion/sql_loader.py\n+++ b/ingestion/sql_loader.py\n@@ -56,4 +56,6 @@\n-query = f"INSERT INTO {schema}.{table} ..."\n+from sqlalchemy import text\n+query = text("INSERT INTO :schema.:table ...")\n+db.execute(query, params)', E'def test_sql_injection_blocked():\n    malicious_source = "x; DROP TABLE users; --"\n    with pytest.raises(Exception):\n        load_data(schema="public", table="events", source=malicious_source)', true, false, 'pending_review', 'mythos-preview', now() - interval '2 hours', 'ingestion/sql_loader.py', 'data-pipeline-etl'),
  ('f1000001-0000-0000-0000-000000000004', 'b1000001-0000-0000-0000-000000000004', 'c1000001-0000-0000-0000-000000000003', 'virtual_patch', E'SecRule ARGS:callback_url "@rx (127\\\\.|10\\\\.|172\\\\.(1[6-9]|2|3[01])\\\\.|192\\\\.168\\\\.|169\\\\.254\\\\.)" "id:100001,deny,status:403"', NULL, NULL, NULL, false, 'deployed', 'mythos-preview', now() - interval '4 hours', 'waf/rules/ssrf-block.conf', 'payment-gateway-v3')
INSERT INTO glasswing_waf_rules (id, root_cause_id, exploit_chain_id, rule_type, rule_expression, rule_description, blocked_requests_count, false_positive_count, is_active, deployed_at, expires_at, blocks_24h, false_positive_rate)
VALUES
  ('aa000001-0000-0000-0000-000000000001', 'b1000001-0000-0000-0000-000000000004', 'd1000001-0000-0000-0000-000000000001', 'modsecurity', 'SecRule ARGS:callback_url "@rx (127\.|10\.|172\.(1[6-9]|2|3[01])\.|192\.168\.|169\.254\.)" "id:100001,deny,status:403"', 'Block SSRF attempts via internal IP ranges in callback URLs', 347, 2, true, now() - interval '4 hours', now() + interval '30 days', 347, 0.006),
  ('aa000001-0000-0000-0000-000000000002', 'b1000001-0000-0000-0000-000000000001', 'd1000001-0000-0000-0000-000000000001', 'modsecurity', 'SecRule REQUEST_BODY "@contains pickle" "id:100002,deny,status:403,msg:Pickle payload detected"', 'Block pickle-serialized payloads in request bodies', 89, 0, true, now() - interval '3 hours', now() + interval '30 days', 89, 0.0),
  ('aa000001-0000-0000-0000-000000000003', 'b1000001-0000-0000-0000-000000000002', 'd1000001-0000-0000-0000-000000000003', 'cloudflare_waf', 'http.request.body contains "COPY" and http.request.body contains "TO" and http.request.uri.path eq "/ingestion/load"', 'Block SQL COPY command injection in ETL ingestion endpoint', 23, 1, true, now() - interval '2 hours', now() + interval '14 days', 23, 0.043)
